class Solution:
    def minSteps(self, s: str, t: str) -> int:
        count_s = {}
        count_t = {}

        for char in s:
            if char in count_s:
                count_s[char] += 1
            else:
                count_s[char] = 1

        for char in t:
            if char in count_t:
                count_t[char] += 1
            else:
                count_t[char] = 1

        steps = 0
        for char in count_s:
            if char in count_t:
                steps += max(0, count_s[char] - count_t[char])
            else:
                steps += count_s[char]

        for char in count_t:
            if char not in count_s:
                steps += count_t[char]

        return steps
```
